unsafe impl Encode for CMFloatBitmap {
    const ENCODING: Encoding = Encoding::Struct(
        "CMFloatBitmap",
        &[
            Encoding::C_ULONG,
            <[*mut c_float; 16]>::ENCODING,
            <usize>::ENCODING,
            <usize>::ENCODING,
            <isize>::ENCODING,
            <isize>::ENCODING,
            <OSType>::ENCODING,
            <CMFloatBitmapFlags>::ENCODING,
        ],
    );
}

